e> valTypes = Ontology.loadAllValueTypes(domain);        long findCount = res.stream()                .filter((valType) -> StringUtils.equalsIgnoreCase(valType.identityValue(), newIdVal))                .count();        // return (findCount > 0);        if (findCount > 0) {            String errMsg = "同名实例(‘" + newIdVal + "’)已存在，不能重复添加";            fieldNameOpt.ifPresentOrElse((fieldName) -> {                msgHandler.addFieldError(context, fieldName, errMsg);            }, () -> {                if (msgHandler instanceof IPluginContext pluginContext) {                    pluginContext.addErrorMessage(context, errMsg);                } else {                    throw new IllegalStateException("msgHandler must be type of " + IPluginContext.class.getSimpleName());                }            });            return false;        }        return true;    }}